import styled from '@emotion/styled';
import { Link } from 'gatsby';

// ============================================================
// Page Layout Styles — 당근(Daangn) 블로그 스타일 재설계
// Stitch MCP 디자인 반영
// ============================================================

export const PageWrapper = styled.main`
  max-width: 1180px;
  margin: 0 auto;
  padding: var(--space-10) var(--space-5);

  @media (min-width: 640px) {
    padding: var(--space-12) var(--space-6);
  }

  @media (min-width: 1024px) {
    padding: var(--space-14) var(--space-8);
  }
`;

export const PageHeader = styled.div`
  margin-bottom: var(--space-12);
`;

export const PageTitle = styled.h1`
  font-size: var(--fs-display-sm);
  font-weight: var(--fw-black);
  color: var(--color-text-primary);
  margin: 0 0 var(--space-3) 0;
  letter-spacing: -0.04em;
  line-height: var(--lh-tight);
  word-break: keep-all;

  @media (min-width: 768px) {
    font-size: var(--fs-display-md);
  }
`;

export const PageSubtitle = styled.p`
  font-size: var(--fs-body-md);
  color: var(--color-text-secondary);
  max-width: 520px;
  margin: 0;
  line-height: var(--lh-relaxed);
  word-break: keep-all;
`;

/* ----------------------------------------------------------
   Hero — 당근 블로그 메인 히어로
   ---------------------------------------------------------- */
export const HeroSection = styled.section`
  margin-bottom: var(--space-16);

  @media (min-width: 768px) {
    margin-bottom: var(--space-20);
  }
`;

export const HeroInner = styled.div`
  display: flex;
  flex-direction: column;
  gap: var(--space-4);
  padding: var(--space-10) 0 var(--space-6);

  @media (min-width: 768px) {
    padding: var(--space-12) 0 var(--space-8);
  }
`;

export const HeroEyebrow = styled.div`
  display: flex;
  align-items: center;
  gap: var(--space-3);
`;

export const HeroBadge = styled.span`
  display: inline-flex;
  align-items: center;
  gap: var(--space-1);
  padding: var(--space-1) var(--space-3);
  background: var(--color-brand-primary);
  color: var(--color-brand-on);
  border-radius: var(--radius-full);
  font-size: var(--fs-xs);
  font-weight: var(--fw-bold);
  letter-spacing: var(--ls-wider);
  text-transform: uppercase;

  &::before {
    content: '';
    display: inline-block;
    width: 6px;
    height: 6px;
    background: var(--color-brand-on);
    border-radius: var(--radius-full);
    opacity: 0.7;
    animation: pulse 2s ease-in-out infinite;
  }

  @keyframes pulse {
    0%, 100% { opacity: 0.7; transform: scale(1); }
    50% { opacity: 1; transform: scale(1.3); }
  }
`;

export const HeroTitle = styled.h1`
  font-size: 2rem;
  font-weight: var(--fw-black);
  color: var(--color-text-primary);
  margin: 0;
  line-height: 1.2;
  letter-spacing: -0.04em;
  word-break: keep-all;
  max-width: 800px;

  @media (min-width: 768px) {
    font-size: 2.75rem;
  }

  @media (min-width: 1024px) {
    font-size: 3.25rem;
  }
`;

export const HeroSubtitle = styled.p`
  font-size: var(--fs-body-lg);
  color: var(--color-text-secondary);
  margin: 0;
  line-height: var(--lh-relaxed);
  max-width: 560px;
  word-break: keep-all;

  @media (min-width: 768px) {
    font-size: var(--fs-title-sm);
  }
`;

export const HeroCTA = styled.div`
  display: flex;
  align-items: center;
  gap: var(--space-3);
  flex-wrap: wrap;
  padding-top: var(--space-2);
`;

export const CTAButton = styled(Link)`
  display: inline-flex;
  align-items: center;
  gap: var(--space-2);
  padding: var(--space-3) var(--space-5);
  background: var(--color-brand-primary);
  color: var(--color-brand-on);
  border-radius: var(--radius-full);
  font-size: var(--fs-body-sm);
  font-weight: var(--fw-semibold);
  text-decoration: none;
  transition: all var(--transition-fast);
  box-shadow: var(--shadow-brand);

  &:hover {
    background: var(--color-brand-hover);
    transform: translateY(-2px);
    box-shadow: 0 6px 24px rgba(255, 126, 54, 0.35);
    color: var(--color-brand-on);
  }

  &:active {
    transform: translateY(0);
  }
`;

export const CTASecondary = styled(Link)`
  display: inline-flex;
  align-items: center;
  gap: var(--space-2);
  padding: var(--space-3) var(--space-5);
  background: transparent;
  color: var(--color-text-primary);
  border: 1.5px solid var(--color-border-default);
  border-radius: var(--radius-full);
  font-size: var(--fs-body-sm);
  font-weight: var(--fw-semibold);
  text-decoration: none;
  transition: all var(--transition-fast);

  &:hover {
    border-color: var(--color-text-primary);
    background: var(--color-interactive-hover);
    color: var(--color-text-primary);
  }
`;

/* ----------------------------------------------------------
   Featured Post — 대형 카드
   ---------------------------------------------------------- */
export const FeaturedCard = styled.article`
  position: relative;
  border-radius: var(--radius-2xl);
  overflow: hidden;
  margin-bottom: var(--space-16);
  background: var(--color-bg-card);
  border: 1px solid var(--color-border-subtle);
  transition:
    box-shadow var(--transition-base),
    transform var(--transition-base),
    border-color var(--transition-base);

  &:hover {
    box-shadow: var(--shadow-card-hover);
    transform: translateY(-4px);
    border-color: transparent;
  }

  @media (min-width: 768px) {
    display: grid;
    grid-template-columns: 1.1fr 1fr;
    min-height: 380px;
  }

  @media (min-width: 1024px) {
    grid-template-columns: 1.2fr 1fr;
    min-height: 420px;
  }
`;

export const FeaturedImageWrapper = styled.div`
  width: 100%;
  aspect-ratio: 16 / 9;
  overflow: hidden;
  background: var(--color-bg-subtle);

  @media (min-width: 768px) {
    aspect-ratio: unset;
    height: 100%;
  }

  .gatsby-image-wrapper {
    width: 100%;
    height: 100%;
  }

  img {
    object-fit: cover;
    width: 100%;
    height: 100%;
    transition: transform var(--transition-slow);
  }

  ${FeaturedCard}:hover & img {
    transform: scale(1.04);
  }
`;

export const FeaturedNoThumbnail = styled.div`
  width: 100%;
  height: 100%;
  min-height: 220px;
  background: linear-gradient(
    145deg,
    var(--color-brand-subtle) 0%,
    var(--color-bg-muted) 100%
  );
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 5rem;
  opacity: 0.3;
`;

export const FeaturedContent = styled.div`
  padding: var(--space-7) var(--space-6);
  display: flex;
  flex-direction: column;
  justify-content: center;
  gap: var(--space-4);

  @media (min-width: 768px) {
    padding: var(--space-10) var(--space-8);
    gap: var(--space-5);
  }
`;

export const FeaturedBadge = styled.div`
  display: flex;
  align-items: center;
  gap: var(--space-3);
`;

export const FeaturedLabel = styled.span`
  display: inline-flex;
  align-items: center;
  padding: 4px var(--space-3);
  background: var(--color-brand-primary);
  color: var(--color-brand-on);
  border-radius: var(--radius-full);
  font-size: var(--fs-xs);
  font-weight: var(--fw-bold);
  letter-spacing: var(--ls-wider);
  text-transform: uppercase;
`;

export const FeaturedCategoryTag = styled.span`
  font-size: var(--fs-xs);
  font-weight: var(--fw-semibold);
  color: var(--color-text-tertiary);
  letter-spacing: var(--ls-wide);
  text-transform: uppercase;
`;

export const FeaturedTitle = styled.h2`
  font-size: var(--fs-title-xl);
  font-weight: var(--fw-black);
  color: var(--color-text-primary);
  margin: 0;
  line-height: 1.2;
  letter-spacing: -0.035em;
  word-break: keep-all;

  @media (min-width: 768px) {
    font-size: var(--fs-display-sm);
  }
`;

export const FeaturedExcerpt = styled.p`
  font-size: var(--fs-body-md);
  color: var(--color-text-secondary);
  margin: 0;
  line-height: var(--lh-relaxed);
  display: -webkit-box;
  -webkit-line-clamp: 3;
  -webkit-box-orient: vertical;
  overflow: hidden;
  word-break: keep-all;
`;

export const FeaturedMeta = styled.div`
  display: flex;
  align-items: center;
  gap: var(--space-2);
  font-size: var(--fs-xs);
  color: var(--color-text-tertiary);
  margin-top: var(--space-1);
`;

export const FeaturedMetaDot = styled.span`
  width: 3px;
  height: 3px;
  background: var(--color-border-strong);
  border-radius: var(--radius-full);
  flex-shrink: 0;
`;

export const FeaturedReadMore = styled.div`
  display: inline-flex;
  align-items: center;
  gap: var(--space-2);
  padding: var(--space-3) var(--space-5);
  background: var(--color-brand-subtle);
  color: var(--color-brand-primary);
  border-radius: var(--radius-full);
  font-size: var(--fs-body-sm);
  font-weight: var(--fw-semibold);
  width: fit-content;
  margin-top: var(--space-2);
  transition: all var(--transition-fast);

  .arrow {
    transition: transform var(--transition-fast);
  }

  ${FeaturedCard}:hover & {
    background: var(--color-brand-primary);
    color: var(--color-brand-on);

    & .arrow {
      transform: translateX(4px);
    }
  }
`;

export const FeaturedLink = styled(Link)`
  text-decoration: none;
  color: inherit;
  display: contents;
`;

/* ----------------------------------------------------------
   Section Header
   ---------------------------------------------------------- */
export const SectionHeader = styled.div`
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: var(--space-8);
`;

export const SectionTitle = styled.h2`
  font-size: var(--fs-title-xl);
  font-weight: var(--fw-extrabold);
  color: var(--color-text-primary);
  margin: 0;
  letter-spacing: -0.03em;

  @media (min-width: 768px) {
    font-size: var(--fs-display-sm);
  }
`;

export const SectionMore = styled(Link)`
  display: inline-flex;
  align-items: center;
  gap: var(--space-1);
  font-size: var(--fs-body-sm);
  color: var(--color-text-secondary);
  font-weight: var(--fw-medium);
  text-decoration: none;
  padding: var(--space-2) var(--space-3);
  border-radius: var(--radius-md);
  transition: all var(--transition-fast);

  .icon {
    transition: transform var(--transition-fast);
  }

  &:hover {
    color: var(--color-brand-primary);
    background: var(--color-brand-subtle);

    & .icon {
      transform: translateX(3px);
    }
  }
`;

/* ----------------------------------------------------------
   Post Grid
   ---------------------------------------------------------- */
export const PostGrid = styled.div`
  display: grid;
  grid-template-columns: 1fr;
  gap: var(--space-5);

  @media (min-width: 600px) {
    grid-template-columns: repeat(2, 1fr);
    gap: var(--space-6);
  }

  @media (min-width: 1024px) {
    grid-template-columns: repeat(3, 1fr);
  }
`;

export const Section = styled.section`
  margin-bottom: var(--space-20);
`;

/* ----------------------------------------------------------
   Empty State
   ---------------------------------------------------------- */
export const EmptyState = styled.div`
  text-align: center;
  padding: var(--space-20) var(--space-4);
  color: var(--color-text-tertiary);

  .emoji {
    font-size: 3.5rem;
    margin-bottom: var(--space-5);
    display: block;
    animation: float 3s ease-in-out infinite;

    @keyframes float {
      0%, 100% { transform: translateY(0); }
      50% { transform: translateY(-8px); }
    }
  }

  h3 {
    font-size: var(--fs-title-md);
    font-weight: var(--fw-bold);
    color: var(--color-text-secondary);
    margin-bottom: var(--space-2);
    letter-spacing: -0.02em;
  }

  p {
    font-size: var(--fs-body-md);
    color: var(--color-text-tertiary);
    line-height: var(--lh-relaxed);
    word-break: keep-all;
  }
`;

/* ----------------------------------------------------------
   하위 호환
   ---------------------------------------------------------- */
export const Hero = styled.section`
  padding: var(--space-12) 0 var(--space-10);
`;

export const HeroSubtitleCompat = styled.p`
  font-size: var(--fs-body-lg);
  color: var(--color-text-secondary);
  max-width: 560px;
  margin: 0;
  line-height: var(--lh-relaxed);
  word-break: keep-all;
`;
